const Background: React.FC<{frame: number}> = ({frame}) => (
  <g>
    <rect width={W} height={H} fill="url(#backgroundGradient)" />
    <ellipse cx="950" cy="555" rx="860" ry="610" fill="url(#ambientGlow)" opacity="0.88" />
    <ellipse cx="1050" cy="1110" rx="1080" ry="380" fill={palette.cyan} opacity="0.03" filter="url(#wideBlur)" />

    <g opacity="0.76">
      {backgroundBars.map((bar, index) => {
        const travel = W + bar.width * 2;
        const raw = bar.offset + frame * bar.speed;
        const wrapped = ((raw % travel) + travel) % travel;
        const x = wrapped - bar.width;
        return (
          <g key={`${bar.y}-${index}`}>
            <rect x={x} y={bar.y} width={bar.width} height={bar.height} rx={bar.height / 2} fill={index % 2 ? palette.blue : palette.cyan} opacity={bar.opacity} filter="url(#barBlur)" />
            <rect x={x + bar.width * 0.12} y={bar.y + bar.height * 0.42} width={bar.width * 0.58} height={Math.max(1.5, bar.height * 0.1)} rx="2" fill={palette.cyanSoft} opacity={bar.opacity * 1.5} />
          </g>
        );
      })}
    </g>

    <g>
      {particles.map((particle, index) => {
        const shimmer = (Math.sin(frame * 0.032 + particle.phase) + 1) / 2;
        return (
          <circle
            key={`${index}-${particle.x}`}
            cx={particle.x + Math.sin(frame * 0.004 + particle.phase) * 3}
            cy={particle.y + Math.cos(frame * 0.003 + particle.phase) * 2}
            r={particle.radius}
            fill={index % 5 ? palette.cyan : palette.white}
            opacity={particle.opacity * (0.5 + shimmer * 0.5)}
          />
        );
      })}
    </g>
  </g>
);

const WorldMap: React.FC<{
  frame: number;
  fps: number;
  durationInFrames: number;
}> = ({frame, fps, durationInFrames}) => {
  const duration = Math.max(1, durationInFrames - 1);
  const reveal = phase(frame, fps, 0.05, 0.95);
  const drift = interpolate(frame, [0, duration], [0, 1], clamp);
  const scale = 0.992 + reveal * 0.006 + drift * 0.004;
  const x = -7 + drift * 10;
  const y = 5 - drift * 8;
  const breathe = (Math.sin(frame * 0.015) + 1) / 2;

  return (
    <g
      transform={`translate(${960 + x} ${540 + y}) scale(${scale}) translate(-960 -540)`}
      opacity={0.28 + reveal * 0.4 + breathe * 0.025}
    >
      <image
        href={WORLD_MAP_DATA_URI}
        x="0"
        y="0"
        width={W}
        height={H}
        preserveAspectRatio="xMidYMid slice"
      />
    </g>
  );
};

const Connectors: React.FC<{
  frame: number;
  fps: number;
}> = ({frame, fps}) => {
  const hold = phase(frame, fps, 3.28, 3.72);
  return (
    <g>
      {connections.map((connection, index) => {
        const draw = phase(
          frame,
          fps,
          connection.startFrame / fps,
          (connection.startFrame + 28) / fps,
          Easing.inOut(Easing.cubic),
        );
        const [fromX, fromY] = connection.from;
        const [toX, toY] = connection.to;
        const pulseProgress = ((frame * 0.0046 + index * 0.137) % 1 + 1) % 1;
        const pulseWindow = Math.pow(Math.sin(pulseProgress * Math.PI), 1.6);
        const pulseX = fromX + (toX - fromX) * pulseProgress;
        const pulseY = fromY + (toY - fromY) * pulseProgress;
        const path = `M ${fromX} ${fromY} L ${toX} ${toY}`;
        const pathLength = Math.hypot(toX - fromX, toY - fromY);
        return (
          <g key={`${fromX}-${toX}-${index}`}>
            <path d={path} fill="none" stroke={palette.cyan} strokeWidth="13" strokeDasharray={`${pathLength} ${pathLength}`} strokeDashoffset={pathLength * (1 - draw)} opacity={0.075 * draw} filter="url(#lineGlow)" />
            <path d={path} fill="none" stroke="url(#connectorGradient)" strokeWidth="2.8" strokeDasharray={`${pathLength} ${pathLength}`} strokeDashoffset={pathLength * (1 - draw)} opacity={0.86 * draw} />
            <path d={path} fill="none" stroke={palette.cyanSoft} strokeWidth="0.75" strokeDasharray="8 12" strokeDashoffset={-frame * 0.75} opacity={draw * 0.5} />
            <circle cx={pulseX} cy={pulseY} r={3.2 + pulseWindow * 2.1} fill={palette.white} opacity={hold * pulseWindow * 0.84} filter="url(#thinGlow)" />
            <circle cx={toX} cy={toY} r={3 + draw * 2} fill={palette.cyanSoft} opacity={draw * 0.82} />
          </g>
        );
      })}
    </g>
  );
};

export const MotionCanvas: React.FC<{
  frame: number;
  fps: number;
  durationInFrames: number;
}> = ({frame, fps, durationInFrames}) => {
  const duration = Math.max(1, durationInFrames - 1);
  const cameraSettle = phase(frame, fps, 0, 2.05);
  const cameraDrift = interpolate(frame, [0, duration], [0, 1], clamp);
  const cameraScale = 0.982 + cameraSettle * 0.018 + cameraDrift * 0.009;
  const cameraX = -10 + cameraDrift * 20;
  const cameraY = 7 - cameraDrift * 14;

  return (
    <svg
      width={W}
      height={H}
      viewBox={`0 0 ${W} ${H}`}
      fill="none"
      xmlns="http://www.w3.org/2000/svg"
      style={{
        position: "absolute",
        inset: 0,
        display: "block",
        overflow: "hidden",
        backgroundColor: palette.ink,
      }}
    >
      <defs>
        <linearGradient id="backgroundGradient" x1="960" y1="0" x2="960" y2="1080" gradientUnits="userSpaceOnUse">
          <stop stopColor="#01050A" />
          <stop offset="0.48" stopColor="#03141F" />
          <stop offset="1" stopColor="#020A11" />
        </linearGradient>
        <radialGradient id="ambientGlow" cx="0" cy="0" r="1" gradientUnits="userSpaceOnUse" gradientTransform="translate(950 520) rotate(90) scale(650 900)">
          <stop stopColor="#0D5972" stopOpacity="0.25" />
          <stop offset="0.48" stopColor="#073044" stopOpacity="0.16" />
          <stop offset="1" stopColor="#020910" stopOpacity="0" />
        </radialGradient>
        <linearGradient id="connectorGradient" x1="0" y1="0" x2="1" y2="0">
          <stop stopColor={palette.violet} />
          <stop offset="0.45" stopColor={palette.cyan} />
          <stop offset="1" stopColor={palette.cyanSoft} />
        </linearGradient>
        <pattern id="scanlinePattern" width="4" height="4" patternUnits="userSpaceOnUse">
          <rect width="4" height="1" fill={palette.white} opacity="0.07" />
        </pattern>
        <filter id="softGlow" x="-80%" y="-80%" width="260%" height="260%">
          <feGaussianBlur stdDeviation="6" result="blur" />
          <feMerge><feMergeNode in="blur" /><feMergeNode in="SourceGraphic" /></feMerge>
        </filter>
        <filter id="thinGlow" x="-80%" y="-80%" width="260%" height="260%">
          <feGaussianBlur stdDeviation="2.4" result="blur" />
          <feMerge><feMergeNode in="blur" /><feMergeNode in="SourceGraphic" /></feMerge>
        </filter>
        <filter id="iconGlow" x="-40%" y="-40%" width="180%" height="180%">
          <feDropShadow dx="0" dy="0" stdDeviation="1.2" floodColor={palette.cyan} floodOpacity="0.28" />
        </filter>
        <filter id="lineGlow" x="-30%" y="-30%" width="160%" height="160%">
          <feGaussianBlur stdDeviation="6" />
        </filter>
        <filter id="barBlur" x="-15%" y="-80%" width="130%" height="260%">
          <feGaussianBlur stdDeviation="8" />
        </filter>
        <filter id="wideBlur" x="-30%" y="-100%" width="160%" height="300%">
          <feGaussianBlur stdDeviation="45" />
        </filter>
      </defs>

      <Background frame={frame} />
      <WorldMap frame={frame} fps={fps} durationInFrames={durationInFrames} />

      <g transform={`translate(${960 + cameraX} ${540 + cameraY}) scale(${cameraScale}) translate(-960 -540)`}>
        <Connectors frame={frame} fps={fps} />
        {nodes.map((node) => (
          <HudNode key={node.id} data={node} frame={frame} fps={fps} />
        ))}
        <CentralHub frame={frame} fps={fps} />
      </g>

      <rect width={W} height={H} fill="url(#scanlinePattern)" opacity="0.15" />
      <rect x="34" y="34" width={W - 68} height={H - 68} rx="28" fill="none" stroke={palette.cyan} strokeWidth="1" opacity="0.09" />

      <g opacity={phase(frame, fps, 3.15, 3.72)} fontFamily="Inter, Arial, sans-serif">
        <text x="78" y="1015" fill={palette.muted} fontSize="14" fontWeight="650" letterSpacing="2.4">STRATEGY INTELLIGENCE / LIVE</text>
        <circle cx="57" cy="1011" r="4" fill={palette.green} filter="url(#thinGlow)" />
        <text x="1842" y="1015" textAnchor="end" fill={palette.muted} fontSize="14" fontWeight="650" letterSpacing="2.4">12 GLOBAL SIGNALS</text>
      </g>
    </svg>
  );
};

export const Motion: React.FC = () => {
  const frame = useCurrentFrame();
  const {fps, durationInFrames} = useVideoConfig();
  return (
    <MotionCanvas
      frame={frame}
      fps={fps}
      durationInFrames={durationInFrames}
    />
  );
};
